mapper.select:
SELECT COUNT(0)
FROM T_BUS_TRATE TBT
JOIN T_BUS_TRATE_CONTRACT TBT_CONTRACT ON TBT.ID = TBT_CONTRACT.TRATE_ID
JOIN T_BUS_TRATE_CUSTOMER TBT_CUSTOMER ON TBT.ID = TBT_CUSTOMER.TRATE_ID
JOIN T_BUS_TRATE_ITEM TBTI ON TBT.ID = TBTI.TRATE_ID
JOIN T_BUS_TRATE_ITEM_CARGO TBTIC ON TBTI.ID = TBTIC.TRATE_ITEM_ID
LEFT JOIN T_BUS_TRATE_ITEM_DETAIL TBTID ON TBTI.ID = TBTID.TRATE_ITEM_ID
WHERE TBT_CONTRACT.CONTRACT_NO = #{contractNo,jdbcType=VARCHAR}
AND TBT_CUSTOMER.CUSTOMER_ID = #{customerId,jdbcType=BIGINT}
AND TBT.START_TIME <= #{endTime,jdbcType=TIMESTAMP}
AND TBT.END_TIME >= #{startTime,jdbcType=TIMESTAMP}
AND TBTIC.CARGO_CODE = #{cargoCode,jdbcType=VARCHAR}

    AND TBT.ID != #{ignoreId,jdbcType=BIGINT}

mapper.insert:
BEGIN

    INSERT INTO T_BUS_TRATE_CONTRACT (ID, TRATE_ID, CONTRACT_NO)
    VALUES (#{contract.id,jdbcType=BIGINT},
    #{contract.trateId,jdbcType=BIGINT},
    #{contract.contractNo,jdbcType=VARCHAR});

END;

BEGIN
INSERT INTO T_BUS_TRATE_CUSTOMER (ID, TRATE_ID, CUSTOMER_ID, CUSTOMER_NAME) VALUES (#{customer.id,jdbcType=BIGINT}, #{customer.trateId,jdbcType=BIGINT}, #{customer.customerId,jdbcType=BIGINT}, #{customer.customerName,jdbcType=VARCHAR});
END;

BEGIN
INSERT INTO T_BUS_TRATE_ITEM (ID, TRATE_ID, TRADE_TYPE, IMP_EXP, IS_TIERED_RATE, PREFERENTIAL_RATE, ORIGIN_ACC_NUMBER) VALUES (#{item.id, jdbcType=BIGINT}, #{item.trateId, jdbcType=BIGINT}, #{item.tradeType, jdbcType=VARCHAR}, #{item.impExp, jdbcType=VARCHAR}, #{item.isTieredRate, jdbcType=VARCHAR}, #{item.preferentialRate, jdbcType=DECIMAL}, #{item.originAccNumber, jdbcType=DECIMAL});
END;

BEGIN
INSERT INTO T_BUS_TRATE_ITEM_CARGO (ID, TRATE_ITEM_ID, CARGO_CODE, CARGO_NAME) VALUES (#{cargo.id,jdbcType=BIGINT}, #{cargo.trateItemId,jdbcType=BIGINT}, #{cargo.cargoCode,jdbcType=VARCHAR}, #{cargo.cargoName,jdbcType=VARCHAR});
END;

BEGIN
INSERT INTO T_BUS_TRATE_ITEM_DETAIL (ID, TRATE_ITEM_ID, BEGIN_TON, END_TON, RATE) VALUES (#{detail.id,jdbcType=BIGINT}, #{detail.trateItemId,jdbcType=BIGINT}, #{detail.beginTon,jdbcType=DECIMAL}, #{detail.endTon,jdbcType=DECIMAL}, #{detail.rate,jdbcType=DECIMAL});
END;

mapper.select:
SELECT TBT.ID, TBT.START_TIME, TBT.END_TIME, TBT.STATUS, TBT.CREATE_BY, TBT.CREATE_BY_NAME, TBT.CREATE_TIME, TBT.UPDATE_BY, TBT.UPDATE_BY_NAME, TBT.UPDATE_TIME FROM T_BUS_TRATE TBT JOIN T_BUS_TRATE_CONTRACT TBT_CONTRACT ON TBT.ID = TBT_CONTRACT.TRATE_ID JOIN T_BUS_TRATE_CUSTOMER TBT_CUSTOMER ON TBT.ID = TBT_CUSTOMER.TRATE_ID JOIN T_BUS_TRATE_ITEM TBTI ON TBT.ID = TBTI.TRATE_ID JOIN T_BUS_TRATE_ITEM_CARGO TBTIC ON TBTI.ID = TBTIC.TRATE_ITEM_ID LEFT JOIN T_BUS_TRATE_ITEM_DETAIL TBTID ON TBTI.ID = TBTID.TRATE_ITEM_ID
AND TBT_CONTRACT.CONTRACT_NO LIKE #{contractNoLike,jdbcType=VARCHAR}
AND TBT_CUSTOMER.CUSTOMER_ID = #{customerId,jdbcType=BIGINT}
GROUP BY TBT.ID, TBT.START_TIME, TBT.END_TIME, TBT.STATUS, TBT.CREATE_BY, TBT.CREATE_BY_NAME, TBT.CREATE_TIME, TBT.UPDATE_BY, TBT.UPDATE_BY_NAME, TBT.UPDATE_TIME ORDER BY TBT.CREATE_TIME DESC

SELECT TBTI.ID, TBTI.TRATE_ID, TBTI.TRADE_TYPE, TBTI.IMP_EXP, TBTI.IS_TIERED_RATE, TBTI.PREFERENTIAL_RATE, TBTI.ORIGIN_ACC_NUMBER, SUM(TCSD."NUMBER") STATEMENT_NUMBER, TBTI.ORIGIN_ACC_NUMBER + SUM(TCSD."NUMBER") ACC_NUMBER FROM T_BUS_TRATE_ITEM TBTI LEFT JOIN (SELECT TCSD.TRATE_ITEM_ID, TCSD."NUMBER" FROM T_COST_STATEMENT TCS JOIN T_COST_STATEMENT_DETAIL TCSD ON TCS.STATUS = '50' AND TCS.ID = TCSD.STATEMENT) TCSD ON TBTI.ID = TCSD.TRATE_ITEM_ID WHERE TBTI.TRATE_ID IN
#{trateId,jdbcType=BIGINT}
GROUP BY TBTI.ID, TBTI.TRATE_ID, TBTI.TRADE_TYPE, TBTI.IMP_EXP, TBTI.IS_TIERED_RATE, TBTI.PREFERENTIAL_RATE, TBTI.ORIGIN_ACC_NUMBER

mapper.update:
UPDATE T_BUS_TRATE_ITEM
SET ORIGIN_ACC_NUMBER = #{originAccNumber,jdbcType=DECIMAL}
WHERE ID = #{id,jdbcType=BIGINT}
